--
-- Table structure for table `bas_material`
--

DROP TABLE IF EXISTS `bas_material`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `bas_material` (
  `id` varchar(36) NOT NULL COMMENT 'ID',
  `category_id` varchar(36) NOT NULL COMMENT '分类',
  `code` varchar(50) NOT NULL COMMENT '编码',
  `name` varchar(100) NOT NULL COMMENT '名称',
  `aux_name` varchar(150) NOT NULL DEFAULT '' COMMENT '助记名',
  `barcode` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '条码',
  `is_enabled` int NOT NULL DEFAULT '1' COMMENT '是否启用',
  `model` varchar(500) DEFAULT NULL COMMENT '规格型号',
  `unit_id` varchar(36) NOT NULL COMMENT '主单位',
  `safety_stock` decimal(18,6) DEFAULT NULL COMMENT '安全库存（最小库存）',
  `image` varchar(2000) DEFAULT NULL COMMENT '图片',
  `sale_price` decimal(18,2) DEFAULT NULL COMMENT '销售价格',
  `tax_code` varchar(50) DEFAULT NULL COMMENT '税控编码',
  `is_sn` int NOT NULL DEFAULT '0' COMMENT '是否启用系列号',
  `remark` varchar(200) DEFAULT NULL COMMENT '备注',
  `create_by` varchar(36) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(36) DEFAULT NULL COMMENT '修改人',
  `update_time` datetime DEFAULT NULL COMMENT '修改时间',
  `version` int DEFAULT NULL COMMENT '版本',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_material_code` (`code`) USING BTREE,
  UNIQUE KEY `uk_material_name` (`name`),
  UNIQUE KEY `uk_material_aux_name` (`aux_name`),
  UNIQUE KEY `uk_material_barcode` (`barcode`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='物料';
/*!40101 SET character_set_client = @saved_cs_client */;

