--
-- Table structure for table `bpmi_instance`
--

DROP TABLE IF EXISTS `bpmi_instance`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `bpmi_instance` (
  `id` varchar(36) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '主键',
  `instance_id` varchar(50) NOT NULL COMMENT '审批实例id',
  `instance_title` varchar(200) DEFAULT NULL,
  `bpm_type` varchar(50) NOT NULL COMMENT 'BPM类型',
  `process_code` varchar(50) NOT NULL COMMENT '审批流程号',
  `bill_type` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '单据类型',
  `bill_id` varchar(50) NOT NULL COMMENT '业务单据id列表',
  `bill_no` varchar(50) DEFAULT NULL COMMENT '业务单据号',
  `is_instance_end` int NOT NULL COMMENT '审批结束',
  `callback_service` varchar(50) DEFAULT NULL COMMENT '回调单据',
  `callback_message` varchar(1000) DEFAULT NULL COMMENT '回调说明',
  `is_callback_ok` int DEFAULT NULL COMMENT '回调成功',
  `create_by` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NOT NULL COMMENT '创建时间',
  `update_by` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '修改人',
  `update_time` datetime DEFAULT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `bpmi_process_instance_instance_id` (`instance_id`,`bpm_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='流程实例记录';
