INSERT INTO `onl_cgform_enhance_js` VALUES ('10058a2951e005773b708af98735aa45','','list',NULL,'4028818370f308e90170f330ff050003'),('109fc068817aada2c7d6c88ffb379010','hidename(){\n  that.sh.name = false;\n}','form',NULL,'4028818370f308e90170f330ff050003'),('274b5d741a0262d3411958f0c465c5f0','genereate_person_config(row){\nconsole.log(\'选择\',row)\nalert(row.name + \'，个人积分配置生成成功！\');\n}','list',NULL,'e2faf977fdaf4b25a524f58c2441a51c'),('2cbaf25f1edb620bea2d8de07f8233a1','air_china_post_materiel_item_onlChange(){\n    return {\n        wl_name(){\n           \n            let id = event.row.id\n            let cnum = event.row.num\n            let value = event.value\n            let targrt = event.target\n            let columnKey = event.column.key\n           let nval = 200*cnum\n           console.log(\'row\',event.row);\n           console.log(\'cnum\',cnum);\n           let otherValues = {\'jifen\': nval}\n              \n                that.triggleChangeValues(targrt,id,otherValues)\n\n        }\n    }\n}','form',NULL,'e67d26b610dd414c884c4dbb24e71ce3'),('35d4ef464e5e8c87c9aa82ea89215fc1','','list',NULL,'e67d26b610dd414c884c4dbb24e71ce3'),('44cad4eec436328ed3cc134855f8d1d5',' onlChange(){\n   return {\n    name(that, event) {\n      that.executeMainFillRule()\n    }\n  }\n }','form',NULL,'4adec929a6594108bef5b35ee9966e9f'),('53b58bff5e4f7d99c5c3ffab79783584','// 获取所有 form data\nvar formData = api.getFormData() || {}\n// 请求后台的填值规则接口地址\nvar url = \'/sys/fillRule/executeRuleByCode/\'\nvar ruleCode = \'stock_io_bill_no\'\napi.get(url + ruleCode, formData).then(res => {\n  // 执行成功，获取返回的值，并赋到页面上\n  if (res.success) {\n    var value = res.result\n    api.setFormData(\'billNo\', value)\n  }\n})','form',NULL,'40288183712beaa901712beaa9a00000'),('55d37886563b57a40cb5db8db78b7043','','form',NULL,'4028818370f308e90170f308eabf0001'),('90394fbc3d48978cc0937bc56f2d5370','','list',NULL,'deea5a8ec619460c9245ba85dbc59e80'),('9ebb26e19e0d9b8fb01d65147c0e12b8','onlChange(){\n   return {\n     \n     materialId(){\n        let value = event.value\n        alert(\'触发控件\',value)\n        \n        if(value!=null && value!=\"\"){\n          let currDate = new Date(value.replace(/-/g, \"\\/\")); \n          let d = new Date(); \n          let ru_year_num = d.getFullYear()-currDate.getFullYear()    \n          let values = {\'ru_year_num\':ru_year_num + 1}\n          that.triggleChangeValues(values)\n        }\n      }\n     \n    }\n }\n','form',NULL,'402881ea71684fa00171684fa0680000');
/*!40000 ALTER TABLE `onl_cgform_enhance_js` ENABLE KEYS */;
