INSERT INTO `onl_cgreport_head` VALUES ('1260569956423487489','stk_in_bill','入库单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.stock_io_type, b.src_no, b.supplier_id, b.op_dept, b.operator, \n       b.settle_amt, b.settled_amt, b.invoiced_amt, b.invoice_type, b.has_swell, b.is_closed, b.has_single\n  FROM stk_io b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2024-08-16 09:36:54','admin','2020-05-13 21:57:53','admin'),('1261479821635354626','stk_out_bill','出库单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.stock_io_type, b.src_no, b.customer_id, b.op_dept, b.operator, \n       b.settle_amt, b.settled_amt, b.has_swell, b.invoiced_amt, b.invoice_type, b.is_closed, b.has_single\n	FROM stk_io b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2023-10-29 21:35:00','admin','2020-05-16 10:13:21','admin'),('1264115611825766401','fin_pur_invoice','采购发票','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.invoice_type, b.invoice_no, b.supplier_id, b.amt, b.is_rubric, b.is_returned, b.is_closed\n	FROM fin_pur_invoice b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-14 10:43:30','admin','2020-05-23 16:47:03','admin'),('1264480038387372034','fin_sal_invoice','销售发票','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.customer_id, b.invoice_type, b.invoice_no,b.amt, b.is_rubric, b.is_returned, b.is_closed\n	FROM fin_sal_invoice b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-14 10:43:17','admin','2020-05-24 16:55:09','admin'),('1531996854281117698','pur_req','采购申请单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.pur_type, b.request_dept, b.requester, b.request_time, b.qty, b.ordered_qty, b.is_closed\n	FROM pur_req b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2024-05-28 22:48:45','admin','2022-06-01 21:51:28','admin'),('1533030649184653313','pur_inquiry','采购询价单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.contact, b.delivery_time, b.delivery_place, b.is_closed\n	FROM pur_inquiry b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-14 10:42:24','admin','2022-06-04 18:19:24','admin'),('1533809073067253761','pur_quot','供应报价单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.src_bill_id, b.src_no, b.supplier_id, \n			 b.delivery_time, b.delivery_place, b.is_closed\n  FROM pur_quot b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-14 10:42:11','admin','2022-06-06 21:52:34','admin'),('1534735349928017922','pur_compare','采购比价单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.src_bill_id, b.src_no, b.payment_method, b.delivery_time, b.delivery_place, b.is_closed\nFROM pur_compare b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-14 10:40:53','admin','2022-06-09 11:13:16','admin'),('1536593055265607681','pur_order','采购订单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.src_no, b.pur_type, b.supplier_id, b.op_dept, b.operator, \n       b.qty, b.amt, b.prepayment_bal, b.in_qty, b.in_cost, b.settle_amt, b.settled_amt, b.invoiced_amt, b.invoice_type,\n       b.payment_method, b.settle_method, b.delivery_time, b.delivery_method, b.delivery_place, b.remark, b.is_closed\n  FROM pur_order b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2023-02-24 15:49:34','admin','2022-06-14 14:15:08','admin'),('1555834511507423233','fin_payment_req','付款申请','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.payment_type, b.supplier_id, b.op_dept, b.operator,\n       b.amt, b.paid_amt, b.remark, b.is_closed\n	FROM fin_payment_req b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2024-05-28 22:49:45','admin','2022-08-06 16:33:48','admin'),('1559410636925984769','sal_quot','销售报价单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.src_no, b.customer_id, b.op_dept, b.operator, b.delivery_place, b.is_closed\n  FROM sal_quot b\n WHERE b.is_effective = 1 AND b.is_voided = 0\n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-14 10:39:59','admin','2022-08-16 13:24:03','admin'),('1559416489922027521','sal_order','销售订单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.src_no, b.customer_id, b.op_dept, b.operator, \n       b.qty, b.amt, b.prereceipt_bal, b.settle_amt, b.settled_amt, b.invoiced_amt, b.invoice_type,\n       b.payment_method, b.settle_method, b.delivery_time, b.delivery_method, b.delivery_place, b.remark, b.is_closed\n  FROM sal_order b\n WHERE b.is_effective = 1 AND b.is_voided = 0 \n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-14 10:39:37','admin','2022-08-16 13:47:18','admin'),('1567797467619110914','fin_receipt_req','(红字)收款申请单','SELECT b.id, b.bill_no, b.bill_date, b.subject, b.receipt_type, b.customer_id, b.op_dept, b.operator, \n       b.amt, b.received_amt, b.remark, b.is_closed\n	FROM fin_receipt_req b\n WHERE b.is_effective = 1 AND b.is_voided = 0\n ORDER BY b.create_time DESC',NULL,NULL,'1',NULL,NULL,NULL,'2024-05-28 22:47:30','admin','2022-09-08 16:50:19','admin'),('1572930989237252098','stk_statistics_inventory_mb','即时库存-物料批次','SELECT MAX(i.id) id, i.material_id, MAX(m.code) material_code, MAX(m.`name`) material_name, MAX(m.`model`) material_model, i.batch_no, i.unit_id, \n       SUM(i.qty) qty, SUM(i.cost) cost, ROUND(SUM(i.cost)/SUM(i.qty),2) unit_cost\n  FROM stk_inventory i\n INNER JOIN bas_material m \n		ON i.material_id = m.id\n WHERE i.is_closed = 0\n GROUP BY i.material_id, i.batch_no, i.unit_id',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:23:36','admin','2022-09-22 20:49:06','admin'),('1573315028393705474','stk_statistics_inventory_m','即时库存-物料','SELECT MAX(i.id) id, i.material_id, MAX(m.code) material_code, MAX(m.`name`) material_name, MAX(m.`model`) material_model, i.unit_id, \n       SUM(i.qty) qty, SUM(i.cost) cost, ROUND(SUM(i.cost)/SUM(i.qty),2) unit_cost\n  FROM stk_inventory i\n INNER JOIN bas_material m \n		ON i.material_id = m.id\n WHERE i.is_closed = 0\n GROUP BY i.material_id, i.unit_id',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:26:06','admin','2022-09-23 22:15:08','admin'),('1573320640724779009','stk_statistics_inventory_wm','即时库存-仓库物料','SELECT MAX(i.id) id, i.material_id, MAX(m.code) material_code, MAX(m.`name`) material_name, MAX(m.`model`) material_model,\n       i.warehouse_id, MAX(w.`name`) warehouse_name, i.unit_id, \n       SUM(i.qty) qty, SUM(i.cost) cost, ROUND(SUM(i.cost)/SUM(i.qty),2) unit_cost\n  FROM stk_inventory i\n INNER JOIN bas_material m \n		ON i.material_id = m.id\n  INNER JOIN bas_warehouse w\n     ON i.warehouse_id = w.id\n WHERE i.is_closed = 0\n GROUP BY i.warehouse_id, i.material_id, i.unit_id',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:18:52','admin','2022-09-23 22:37:26','admin'),('1573695541629427714','stk_statistics_io_detail','出入库明细','SELECT e.id, b.bill_no, b.bill_date, b.stock_io_type, b.customer_id, b.supplier_id, e.warehouse_id, \n       e.material_id, m.`code` material_code, m.`name` material_name, m.model material_model, e.batch_no, e.unit_id, \n			 CASE e.stock_io_direction WHEN \'1\' THEN e.qty ELSE NULL END in_qty, \n			 CASE e.stock_io_direction WHEN \'1\' THEN e.cost ELSE NULL END in_cost, \n			 CASE e.stock_io_direction WHEN \'2\' THEN e.qty ELSE NULL END out_qty, \n			 CASE e.stock_io_direction WHEN \'2\' THEN e.cost ELSE NULL END out_cost,\n			 CASE e.qty WHEN 0 THEN NULL ELSE ROUND(e.cost/e.qty, 2) END unit_cost\n  FROM stk_io b\n INNER JOIN stk_io_entry e\n    ON b.id = e.mid\n INNER JOIN bas_material m \n		ON e.material_id = m.id\n WHERE b.is_effective = 1 AND b.is_voided = 0\n',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:13:37','admin','2022-09-24 23:27:10','admin'),('1575380033020686337','stk_statistics_io_month_sum_wm','出入库月汇总-仓库物料','SELECT MAX(s.id) id, s.`year`, s.`month`, s.warehouse_id, s.material_id, s.unit_id, \n       MAX(m.code) material_code, MAX(m.model) material_model,\n       SUM(s.begin_qty) begin_qty, SUM(s.begin_cost) begin_cost, \n       SUM(s.in_qty) in_qty, SUM(s.in_cost) in_cost, SUM(s.out_qty) out_qty, SUM(s.out_cost) out_cost,\n       SUM(s.bal_qty) bal_qty, SUM(s.bal_cost) bal_cost\n  FROM stk_io_sum s\n INNER JOIN bas_material m ON s.material_id = m.id\n GROUP BY s.`year`, s.`month`, s.warehouse_id, s.material_id, s.unit_id',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-15 11:07:05','admin','2022-09-29 15:00:44','admin'),('1578398668198854657','fin_statistics_receivable_month_sum','应收月汇总','SELECT s.id, s.`year`, s.`month`, s.customer_id, IFNULL(c.`name`, \'（全部）\') customer_name, s.begin_debit_bal, s.debit_amt, s.credit_amt, s.debit_bal\n  FROM fin_receivable_sum s \n  LEFT JOIN bas_customer c ON s.customer_id = c.id\n WHERE s.`year`*100 + s.`month` < (SELECT `year`*100 + `month` FROM bas_biz_period LIMIT 1)',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:09:26','admin','2022-10-07 22:55:42','admin'),('1578557943487479809','fin_statistics_receivable_detail','应收明细','SELECT a.id, a.bill_no, a.bill_date, a.customer_id, a.op_dept, a.operator, \n       CONCAT(\'FinReceivable:\',a.receivable_type) bill_type, a.amt debit_amt, NULL credit_amt, a.effective_time\n  FROM fin_receivable a\n WHERE a.is_effective = 1 AND a.is_voided = 0\nUNION ALL\nSELECT b.id, b.bill_no, b.bill_date, b.customer_id, NULL, NULL, \n       CONCAT(\'FinReceipt:\',b.receipt_type) bill_type, NULL debit_amt, b.amt credit_amt, b.effective_time\n  FROM fin_receipt b\n WHERE b.is_effective = 1 AND b.is_voided = 0\n',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:08:11','admin','2022-10-08 09:28:37','admin'),('1578581972927725569','fin_statistics_receivable_check','应收对账','SELECT a.id, a.bill_no, a.bill_date, a.customer_id, a.op_dept, a.operator, CONCAT(\'FinReceivable:\',a.receivable_type) bill_type, \n       a.amt, a.checked_amt, a.amt - a.checked_amt unchecked_amt, \n       CASE WHEN a.amt = a.checked_amt THEN \'Y\' WHEN a.checked_amt = 0 THEN \'N\' ELSE \'P\' END check_flag, a.effective_time\n  FROM fin_receivable a\n WHERE a.is_effective = 1 AND a.is_voided = 0\n UNION ALL\nSELECT b.id, b.bill_no, b.bill_date, b.customer_id, null, null, CONCAT(\'FinReceipt:\',b.receipt_type) bill_type, \n       b.amt, b.checked_amt, b.amt - b.checked_amt unchecked_amt, \n       CASE WHEN b.amt = b.checked_amt THEN \'Y\' WHEN b.checked_amt = 0 THEN \'N\' ELSE \'P\' END check_flag, b.effective_time\n  FROM fin_receipt b\n WHERE b.is_effective = 1 AND b.is_voided = 0',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:06:23','admin','2022-10-08 11:04:06','admin'),('1578657557905489921','fin_statistics_payable_detail','应付明细','SELECT a.id, a.bill_no, a.bill_date, a.supplier_id, a.op_dept, a.operator, \n       CONCAT(\'FinPayable:\',a.payable_type) bill_type, NULL debit_amt, a.amt credit_amt, a.effective_time\n  FROM fin_payable a\n WHERE a.is_effective = 1 AND a.is_voided = 0\nUNION ALL\nSELECT b.id, b.bill_no, b.bill_date, b.supplier_id, NULL, NULL, \n       CONCAT(\'FinPayment:\',b.payment_type) bill_type, b.amt debit_amt, NULL credit_amt, b.effective_time\n  FROM fin_payment b\n WHERE b.is_effective = 1 AND b.is_voided = 0\n',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:05:04','admin','2022-10-08 16:04:27','admin'),('1578658427363737601','fin_statistics_payable_check','应付对账','SELECT a.id, a.bill_no, a.bill_date, a.supplier_id, a.op_dept, a.operator, CONCAT(\'FinPayable:\',a.payable_type) bill_type, \n       a.amt, a.checked_amt, a.amt - a.checked_amt unchecked_amt, \n       CASE WHEN a.amt = a.checked_amt THEN \'Y\' WHEN a.checked_amt = 0 THEN \'N\' ELSE \'P\' END check_flag, a.effective_time\n  FROM fin_payable a\n WHERE a.is_effective = 1 AND a.is_voided = 0\n UNION ALL\nSELECT b.id, b.bill_no, b.bill_date, b.supplier_id, null, null, CONCAT(\'FinPayment:\',b.payment_type) bill_type, \n       b.amt, b.checked_amt, b.amt - b.checked_amt unchecked_amt, \n       CASE WHEN b.amt = b.checked_amt THEN \'Y\' WHEN b.checked_amt = 0 THEN \'N\' ELSE \'P\' END check_flag, b.effective_time\n  FROM fin_payment b\n WHERE b.is_effective = 1 AND b.is_voided = 0',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:03:41','admin','2022-10-08 16:07:54','admin'),('1578658883720790018','fin_statistics_payable_month_sum','应付月汇总','SELECT p.id, p.`year`, p.`month`, p.supplier_id, IFNULL(s.`name`, \'（全部）\') supplier_name, p.begin_credit_bal, p.debit_amt, p.credit_amt, p.credit_bal\n  FROM fin_payable_sum p \n  LEFT JOIN bas_supplier s ON p.supplier_id = s.id\n WHERE p.`year`*100 + p.`month` < (SELECT `year`*100 + `month` FROM bas_biz_period LIMIT 1)',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 22:01:53','admin','2022-10-08 16:09:43','admin'),('1579758928603910145','home_sale','首页-销售','SELECT * FROM home_sale',NULL,NULL,'1',NULL,NULL,NULL,'2022-10-14 17:51:28','admin','2022-10-11 17:00:54','admin'),('1579760837406494722','home_purchase','首页-采购','SELECT * FROM home_purchase',NULL,NULL,'1',NULL,NULL,NULL,'2022-10-14 20:17:26','admin','2022-10-11 17:08:29','admin'),('1579838131626053634','fin_payable_bal','应付即时余额','SELECT * FROM fin_payable_bal',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 21:26:44','admin','2022-10-11 22:15:37','admin'),('1579838441006305281','fin_receivable_bal','应收即时余额','SELECT * FROM fin_receivable_bal',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 21:26:09','admin','2022-10-11 22:16:51','admin'),('1579848144423751681','home_summary','首页-概况','SELECT \'即时库存(元)\' label, IFNULL(SUM(cost), 0) `value`, 8 width FROM stk_inventory\nUNION\nSELECT \'客户欠款(元)\', IFNULL(SUM(debit_bal), 0), 8 FROM fin_receivable_bal\nUNION\nSELECT \'欠供应商(元)\', IFNULL(SUM(credit_bal), 0), 8 FROM fin_payable_bal\n',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-01 11:06:26','admin','2022-10-11 22:55:24','admin'),('1580373857203654658','sal_statistics_order_sum','销售订单汇总','SELECT MAX(b.id) id, YEAR(b.bill_date) `year`, MONTH(b.bill_date) `month`, \n       COUNT(1) order_count, SUM(b.amt) amt, SUM(b.out_cost) out_cost, \n       SUM(b.settle_amt) settle_amt, SUM(b.settled_amt) settled_amt, SUM(b.settle_amt) - SUM(b.settled_amt) unsettled_amt,\n       SUM(b.gross_profit) gross_profit, ROUND(SUM(b.gross_profit)*100/SUM(b.ex_tax_settle_amt), 2) gross_margin\n  FROM sal_order b \n WHERE b.is_effective = 1 AND b.is_voided = 0\n GROUP BY YEAR(b.bill_date), MONTH(b.bill_date)\n',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 21:12:51','admin','2022-10-13 09:44:24','admin'),('1580375344147337218','pur_statistics_order_sum','采购订单汇总','SELECT MAX(b.id) id, YEAR(b.bill_date) `year`, MONTH(b.bill_date) `month`,\n       COUNT(1) order_count, SUM(b.amt) amt, SUM(b.in_cost) in_cost, SUM(b.settle_amt) settle_amt, SUM(b.settled_amt) settled_amt,\n       SUM(b.settle_amt) - SUM(b.settled_amt) unsettled_amt\n  FROM pur_order b\n WHERE b.is_effective = 1 AND b.is_voided = 0\n GROUP BY YEAR(b.bill_date), MONTH(b.bill_date)',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-26 21:11:03','admin','2022-10-13 09:50:19','admin'),('1580740609854935042','home_customer','首页-客户','SELECT \'今日+\' label, COUNT(1) value, 5 width\n  FROM bas_customer \n WHERE is_enabled = 1 \n   AND create_time >= DATE(SYSDATE())\n UNION\nSELECT \'本周+\', COUNT(1), 5 \n  FROM bas_customer \n WHERE is_enabled = 1 \n   AND YEARWEEK(create_time, 1) = YEARWEEK(SYSDATE(), 1)\n UNION\nSELECT \'本月+\', COUNT(1), 6\n  FROM bas_customer \n WHERE is_enabled = 1 \n   AND YEAR(create_time) = YEAR(SYSDATE()) AND MONTH(create_time) = MONTH(SYSDATE())\nUNION\nSELECT \'客户数\', COUNT(1), 8\n  FROM bas_customer \n WHERE is_enabled = 1 \n',NULL,NULL,'1',NULL,NULL,NULL,'2022-10-16 10:22:02','admin','2022-10-14 10:01:45','admin'),('1580740795561938946','home_supplier','首页-供应商','SELECT \'今日+\' label, COUNT(1) value, 5 width\n  FROM bas_supplier \n WHERE is_enabled = 1 \n   AND create_time >= DATE(SYSDATE())\n UNION\nSELECT \'本周+\', COUNT(1), 5\n  FROM bas_supplier \n WHERE is_enabled = 1 \n   AND YEARWEEK(create_time, 1) = YEARWEEK(SYSDATE(), 1)\n UNION\nSELECT \'本月+\', COUNT(1), 6 \n  FROM bas_supplier \n WHERE is_enabled = 1 \n   AND YEAR(create_time) = YEAR(SYSDATE()) AND MONTH(create_time) = MONTH(SYSDATE())\nUNION\nSELECT \'供应商数\', COUNT(1), 8 \n  FROM bas_supplier \n WHERE is_enabled = 1 \n',NULL,NULL,'1',NULL,NULL,NULL,'2022-10-16 10:21:14','admin','2022-10-14 10:02:29','admin'),('1580915783778701314','home_sale_amt','首页-销售金额','SELECT CONCAT(MAX(MONTH(b.bill_date)), \'月\') x, IFNULL(SUM(b.amt),0) y\n  FROM sal_order b \n WHERE b.is_effective = 1 AND b.is_voided = 0\n   AND b.bill_date BETWEEN fn_first_day(DATE_ADD(SYSDATE(), INTERVAL -11 MONTH)) AND LAST_DAY(SYSDATE())\n GROUP BY YEAR(b.bill_date), MONTH(b.bill_date)\n ORDER BY YEAR(b.bill_date), MONTH(b.bill_date)\n',NULL,NULL,'1',NULL,NULL,NULL,'2022-10-14 21:49:06','admin','2022-10-14 21:37:50','admin'),('1580918054310645761','home_gross_profit','首页-毛利润','SELECT CONCAT(MAX(MONTH(b.bill_date)), \'月\') x, IFNULL(SUM(b.gross_profit),0) y\n  FROM sal_order b \n WHERE b.is_effective = 1 AND b.is_voided = 0\n   AND b.bill_date BETWEEN fn_first_day(DATE_ADD(SYSDATE(), INTERVAL -11 MONTH)) AND LAST_DAY(SYSDATE())\n GROUP BY YEAR(b.bill_date), MONTH(b.bill_date)\n ORDER BY YEAR(b.bill_date), MONTH(b.bill_date)\n',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-15 10:24:20','admin','2022-10-14 21:46:51','admin'),('1580918550912045057','home_purchase_amt','首页-采购金额','SELECT CONCAT(MAX(MONTH(b.bill_date)), \'月\') x, IFNULL(SUM(b.amt),0) y\n  FROM pur_order b \n WHERE b.is_effective = 1 AND b.is_voided = 0\n   AND b.bill_date BETWEEN fn_first_day(DATE_ADD(SYSDATE(), INTERVAL -11 MONTH)) AND LAST_DAY(SYSDATE())\n GROUP BY YEAR(b.bill_date), MONTH(b.bill_date)\n ORDER BY YEAR(b.bill_date), MONTH(b.bill_date)\n',NULL,NULL,'1',NULL,NULL,NULL,'2022-10-25 15:19:41','admin','2022-10-14 21:48:49','admin'),('1580923428333948929','home_stock_bal_cost','首页-库存结存金额','SELECT CONCAT(s.`month`, \'月\') x, IFNULL(SUM(s.bal_cost), 0) y\n  FROM stk_io_sum s\n WHERE s.`year`*100 + s.`month` \n       BETWEEN (SELECT PERIOD_ADD(`year`*100 + `month`, - 12) FROM bas_biz_period LIMIT 1) \n           AND (SELECT PERIOD_ADD(`year`*100 + `month`, - 1) FROM bas_biz_period LIMIT 1)\nGROUP BY s.`year`, s.`month`\nORDER BY s.`year`, s.`month`',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-13 22:05:18','admin','2022-10-14 22:08:12','admin'),('1582194686237454338','home_doing_bill','首页-处理中单据','SELECT * FROM home_doing_bill',NULL,NULL,'1',NULL,NULL,NULL,'2022-11-15 14:35:36','admin','2022-10-18 10:19:44','admin'),('1708432028035207169','stk_io_single_detail','出入库明细SN','SELECT s.id, b.bill_no, b.bill_date, b.stock_io_type, b.customer_id, b.supplier_id, s.warehouse_id, \n       s.material_id, m.`code` material_code, m.`name` material_name, m.model material_model, s.batch_no, s.sn, s.unit_id, \n			 CASE s.stock_io_direction WHEN \'1\' THEN s.qty ELSE NULL END in_qty, \n			 CASE s.stock_io_direction WHEN \'1\' THEN s.cost ELSE NULL END in_cost, \n			 CASE s.stock_io_direction WHEN \'2\' THEN s.qty ELSE NULL END out_qty, \n			 CASE s.stock_io_direction WHEN \'2\' THEN s.cost ELSE NULL END out_cost\n  FROM stk_io b\n INNER JOIN stk_io_single s\n    ON b.id = s.mid\n INNER JOIN bas_material m \n		ON s.material_id = m.id\n WHERE b.is_effective = 1 AND b.is_voided = 0\n',NULL,NULL,'1',NULL,NULL,NULL,'2023-10-01 20:55:45','admin','2023-10-01 18:41:51','admin'),('1739673605953884162','bas_bom','BOM','SELECT b.id, b.code, b.name, b.aux_name, b.material_id, m.model AS material_model, b.unit_id, b.remark\n  FROM bas_bom b INNER JOIN bas_material m ON b.material_id = m.id\n WHERE b.is_enabled = 1',NULL,NULL,'1',NULL,NULL,NULL,'2023-12-27 00:18:19','admin','2023-12-26 23:44:44','admin'),('1773693208680726530','bas_material','物料','SELECT id, code, name, aux_name, model, category_id, unit_id, sale_price, barcode\n  FROM bas_material\n WHERE is_enabled = 1\n ORDER BY code',NULL,NULL,'1',NULL,NULL,NULL,'2024-06-07 13:56:56','admin','2024-03-29 20:46:29','admin'),('1796540450559004676','home_receipt_payment','首页-收支','SELECT * FROM home_receipt_payment',NULL,NULL,'1',NULL,NULL,NULL,'2026-03-10 13:23:07','admin','2026-03-10 13:23:07','admin'),('49d9b3c81f5647dea5b4d1f431613920','stk_inventory_batch','库存批次','SELECT i.id, i.material_id, m.aux_name material_name, m.barcode barcode, m.model material_model, \n       i.batch_no, i.warehouse_id, i.unit_id, i.qty, i.cost, \n			 i.is_single_supplier, i.supplier_id\n  FROM stk_inventory i \n INNER JOIN bas_material m \n    ON i.material_id = m.id\n WHERE i.is_closed = 0\n ORDER BY i.create_time DESC\n \n',NULL,NULL,'1',NULL,NULL,NULL,'2024-07-07 11:39:10','admin','2020-05-02 11:44:34','admin'),('6c7f59741c814347905a938f06ee003c','report_user','统计在线用户','select * from sys_user',NULL,NULL,'1',NULL,NULL,NULL,'2019-11-22 16:34:31','admin','2019-03-25 11:20:45','admin'),('87b55a515d3441b6b98e48e5b35474a6','demo','Report Demo','select * from demo',NULL,NULL,'1',NULL,NULL,NULL,'2019-03-15 18:18:17','admin','2019-03-12 11:25:16','admin');
