DROP TABLE IF EXISTS `sal_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sal_order` (
  `id` varchar(36) NOT NULL COMMENT 'ID',
  `bill_no` varchar(50) NOT NULL COMMENT '单据编号',
  `bill_date` date NOT NULL COMMENT '单据日期',
  `src_bill_type` varchar(50) DEFAULT NULL COMMENT '源单类型',
  `src_bill_id` varchar(36) DEFAULT NULL COMMENT '源单id',
  `src_no` varchar(50) DEFAULT NULL COMMENT '源单号',
  `subject` varchar(200) DEFAULT NULL COMMENT 'subject',
  `is_rubric` int NOT NULL DEFAULT '0' COMMENT '是否红字',
  `customer_id` varchar(36) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '客户',
  `contact` varchar(50) DEFAULT NULL COMMENT '联系人',
  `phone` varchar(100) DEFAULT NULL COMMENT '联系电话',
