CREATE DEFINER=`psi`@`localhost` PROCEDURE `sp_fin_receivable_sum`(IN `p_year` smallint,IN `p_month` tinyint)
BEGIN
	DECLARE n_year SMALLINT;
	DECLARE n_month TINYINT;

	DROP TABLE IF EXISTS `tmp`;
	CREATE TEMPORARY TABLE tmp(
		customer_id VARCHAR(36),
		amt DECIMAL(18,2) DEFAULT 0
	);
	
	
	UPDATE fin_receivable_sum b 
		 SET b.debit_amt = 0, b.credit_amt = 0
	 WHERE b.`year` = p_year
	   AND b.`month` = p_month;

	
	INSERT INTO tmp(customer_id, amt)
		SELECT r.customer_id, SUM(r.amt) amt
			FROM fin_receivable r
		 WHERE r.is_effective = 1 
			 AND r.is_voided = 0
			 AND r.bill_date BETWEEN fn_first_day_of_ym(p_year, p_month) AND fn_last_day_of_ym(p_year, p_month)
		 GROUP BY r.customer_id;

	UPDATE fin_receivable_sum b
	 INNER JOIN tmp a
			ON b.customer_id = a.customer_id
		 AND b.`year` = p_year
		 AND b.`month` = p_month
		 SET b.debit_amt = a.amt;

	
	INSERT INTO fin_receivable_sum(id, `year`, `month`, customer_id, begin_debit_bal, debit_amt, credit_amt)
		SELECT UUID_SHORT(), p_year, p_month, a.customer_id, 0, a.amt, 0
			FROM tmp a
			LEFT JOIN fin_receivable_sum b
				ON a.customer_id = b.customer_id
			 AND b.`year` = p_year
			 AND b.`month` = p_month
		 WHERE b.customer_id IS NULL;

	SELECT IFNULL(SUM(amt), 0) INTO @debit_amt FROM tmp;

	DELETE FROM tmp;
	
	
	INSERT INTO tmp(customer_id, amt)
		SELECT r.customer_id, SUM(r.amt) amt
			FROM fin_receipt r
		 WHERE r.is_effective = 1 
			 AND r.is_voided = 0
			 AND r.bill_date BETWEEN fn_first_day_of_ym(p_year, p_month) AND fn_last_day_of_ym(p_year, p_month)
		 GROUP BY r.customer_id;

	UPDATE fin_receivable_sum b
	 INNER JOIN tmp a
			ON b.customer_id = a.customer_id
		 AND b.`year` = p_year
		 AND b.`month` = p_month
		 SET b.credit_amt = a.amt;

	
	INSERT INTO fin_receivable_sum(id, `year`, `month`, customer_id, begin_debit_bal, debit_amt, credit_amt)
		SELECT UUID_SHORT(), p_year, p_month, a.customer_id, 0, 0, a.amt
			FROM tmp a
			LEFT JOIN fin_receivable_sum b
				ON a.customer_id = b.customer_id
			 AND b.`year` = p_year
			 AND b.`month` = p_month
		 WHERE b.customer_id IS NULL;	

	SELECT IFNULL(SUM(amt), 0) INTO @credit_amt FROM tmp;


	
	SELECT COUNT(b.id) 
		INTO @num
		FROM fin_receivable_sum b
	 WHERE b.`year` = p_year
		 AND b.`month` = p_month
		 AND b.customer_id IS NULL;

	IF @num = 0 THEN
		INSERT INTO fin_receivable_sum(id, `year`, `month`, customer_id, begin_debit_bal, debit_amt, credit_amt)
			SELECT UUID_SHORT(), p_year, p_month, NULL, IFNULL(SUM(b.begin_debit_bal), 0), IFNULL(SUM(b.debit_amt), 0), IFNULL(SUM(b.credit_amt),0)
				FROM fin_receivable_sum b
			 WHERE b.`year` = p_year
				 AND b.`month` = p_month
				 AND b.customer_id IS NOT NULL;
	ELSE
		UPDATE fin_receivable_sum b 
			 SET b.debit_amt = @debit_amt, b.credit_amt = @credit_amt
		 WHERE b.`year` = p_year
			 AND b.`month` = p_month
			 AND b.customer_id IS NULL;
	END IF;

  
	UPDATE fin_receivable_sum b 
		 SET b.debit_bal = IFNULL(b.begin_debit_bal,0) + IFNULL(b.debit_amt,0) - IFNULL(b.credit_amt,0)
	 WHERE b.`year` = p_year
		 AND b.`month` = p_month;

	
	IF p_month < 12 THEN
		SET @n_year = p_year, @n_month = p_month + 1;
	ELSE
		SET @n_year = p_year + 1, @n_month = 1;
	END IF;

	DELETE FROM fin_receivable_sum
	 WHERE `year` = @n_year
		 AND `month` = @n_month;

	INSERT INTO fin_receivable_sum(id, `year`, `month`, customer_id, begin_debit_bal, debit_amt, credit_amt)
		SELECT UUID_SHORT(), @n_year, @n_month, IFNULL(b.customer_id, c.id), b.debit_bal, 0, 0
			FROM fin_receivable_sum b
			LEFT JOIN bas_customer c
				ON b.customer_id = c.id
       AND c.is_enabled = 1
		 WHERE b.debit_bal != 0
			 AND b.`year` = p_year
			 AND b.`month` = p_month;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_stk_io_sum` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
