/*!50001 VIEW `fin_payable_bal` AS select `c`.`id` AS `id`,`c`.`id` AS `supplier_id`,`c`.`name` AS `supplier_name`,((ifnull(`s`.`begin_credit_bal`,0) + ifnull(`pyb`.`amt`,0)) - ifnull(`pyt`.`amt`,0)) AS `credit_bal` from (((`bas_supplier` `c` left join `fin_payable_sum` `s` on(((`c`.`id` = `s`.`supplier_id`) and (((`s`.`year` * 100) + `s`.`month`) = (select ((`bas_biz_period`.`year` * 100) + `bas_biz_period`.`month`) from `bas_biz_period` limit 1))))) left join (select `fin_payable`.`supplier_id` AS `supplier_id`,sum(`fin_payable`.`amt`) AS `amt` from `fin_payable` where ((`fin_payable`.`is_effective` = 1) and (`fin_payable`.`is_voided` = 0) and (`fin_payable`.`bill_date` >= (select `fn_first_day_of_ym`(`bas_biz_period`.`year`,`bas_biz_period`.`month`) from `bas_biz_period` limit 1))) group by `fin_payable`.`supplier_id`) `pyb` on((`c`.`id` = `pyb`.`supplier_id`))) left join (select `fin_payment`.`supplier_id` AS `supplier_id`,sum(`fin_payment`.`amt`) AS `amt` from `fin_payment` where ((`fin_payment`.`is_effective` = 1) and (`fin_payment`.`is_voided` = 0) and (`fin_payment`.`bill_date` >= (select `fn_first_day_of_ym`(`bas_biz_period`.`year`,`bas_biz_period`.`month`) from `bas_biz_period` limit 1))) group by `fin_payment`.`supplier_id`) `pyt` on((`c`.`id` = `pyt`.`supplier_id`))) where (`c`.`is_enabled` = 1) */;
